/**
 * Integration tests for VerificationPlayground component (source-level).
 *
 * The component uses React hooks (useAtomValue, useAtomSet) which cannot be
 * rendered in a non-React environment, so these tests verify implementation
 * patterns via source-code inspection. Behavioral logic is covered by unit
 * tests for verification-utils.ts (getVerificationDisabledState).
 *
 * RED phase: these tests fail until VerificationPlayground.tsx is fully
 * implemented (the current stub does not contain these patterns).
 */

import { describe, it, expect } from "bun:test"
import { readFileSync, existsSync } from "node:fs"
import path from "node:path"

const COMPONENT_PATH = path.join(
  import.meta.dir,
  "../../components/interactive/VerificationPlayground.tsx",
)

const source = readFileSync(COMPONENT_PATH, "utf-8")

describe("VerificationPlayground — source constraints", () => {
  it("file exists", () => {
    expect(existsSync(COMPONENT_PATH)).toBe(true)
  })

  it("has 'use client' directive", () => {
    expect(source).toContain('"use client"')
  })

  it("is a named export", () => {
    expect(source).toContain("export function VerificationPlayground")
  })
})

describe("VerificationPlayground — initial render: message input + buttons", () => {
  it("contains a text input for message", () => {
    // Component must render a text input for the message
    expect(source).toMatch(/type="text"|<textarea/)
  })

  it("contains 'Generate Keypair' button label", () => {
    expect(source).toContain("Generate Keypair")
  })

  it("contains 'Sign' and 'Verify' in the button label", () => {
    expect(source).toContain("Sign")
    expect(source).toContain("Verify")
  })
})

describe("VerificationPlayground — disabled states", () => {
  it("uses getVerificationDisabledState helper (not inline logic)", () => {
    expect(source).toContain("getVerificationDisabledState")
  })

  it("wires canSign to the Sign & Verify button disabled prop", () => {
    expect(source).toContain("canSign")
  })

  it("wires canGenerate to the Generate Keypair button disabled prop", () => {
    expect(source).toContain("canGenerate")
  })
})

describe("VerificationPlayground — generating state", () => {
  it("shows 'Generating...' text during keygen in-flight", () => {
    expect(source).toContain("Generating")
  })

  it("guards on generating-keypair step for button label", () => {
    expect(source).toContain("generating-keypair")
  })
})

describe("VerificationPlayground — success result UI", () => {
  it("shows success state with checkmark for valid signature", () => {
    // Must contain a visual success indicator
    expect(source).toMatch(/✓|"valid"|falcon-success/)
  })

  it("shows duration (durationMs) in the result", () => {
    expect(source).toContain("durationMs")
  })

  it("guards on 'complete' step to show result UI", () => {
    expect(source).toContain('"complete"')
  })
})

describe("VerificationPlayground — error result UI", () => {
  it("shows error state with 'error' class or red indicator", () => {
    expect(source).toMatch(/falcon-error|✗|"error"/)
  })

  it("displays error message from step state", () => {
    expect(source).toContain("step.message")
  })

  it("guards on 'error' step to show error UI", () => {
    expect(source).toContain('"error"')
